// A debounce function to delay the execution of a function until a certain amount of time has passed without it being called again.
function debounce(func, wait) {
    let timeout;
    return function(...args) {
        clearTimeout(timeout);
        timeout = setTimeout(() => func.apply(this, args), wait);
    };
}

// Example usage:
const handleResize = () => console.log('Window resized!');
const debouncedHandleResize = debounce(handleResize, 300);

window.addEventListener('resize', debouncedHandleResize);
```

This code defines a `debounce` function that delays the execution of a given function (`func`) until a specified amount of time (`wait`) has passed without the function being called again. The example demonstrates how to use this function to log a message only after the window has stopped resizing for 300 milliseconds.
